// Numeric const enum example
const enum Direction {
  Up = 1,
  Down = 2,
  Left = 3,
  Right = 4
}

let move: Direction = Direction.Up;
console.log(move); // 1
// move = 5; // Error: 5 is not assignable to Direction

// String const enum example
const enum Role {
  Admin = 'ADMIN',
  User = 'USER',
  Guest = 'GUEST'
}

let userRole: Role = Role.Admin;
console.log(userRole); // ADMIN
// userRole = 'SUPERUSER'; // Error: SUPERUSER is not assignable to Role

// Regular enum vs. const enum
enum Status {
  Active = 1,
  Inactive = 2
}

const enum ConstStatus {
  Active = 1,
  Inactive = 2
}

let regularStatus: Status = Status.Active;
let constStatus: ConstStatus = ConstStatus.Active;

console.log(regularStatus); // 1
console.log(Status[1]); // Active
console.log(constStatus); // 1
// console.log(ConstStatus[1]); // Error: Const enums do not support reverse mapping

// Const enums vs. type aliases
const enum Priority {
  Low = 1,
  Medium = 2,
  High = 3
}

type PriorityAlias = 1 | 2 | 3;

let enumPriority: Priority = Priority.Low;
let aliasPriority: PriorityAlias = 1;

console.log(enumPriority); // 1
console.log(aliasPriority); // 1
// enumPriority = 4; // Error: 4 is not assignable to Priority
// aliasPriority = 4; // Error: 4 is not assignable to PriorityAlias

// Const enums in functions
const enum StatusCode {
  Success = 200,
  NotFound = 404,
  Error = 500
}

function getStatusMessage(code: StatusCode): string {
  return `Status code: ${code}`;
}

let response: StatusCode = StatusCode.Success;
console.log(getStatusMessage(response)); // Status code: 200
response = StatusCode.Error;
console.log(getStatusMessage(response)); // Status code: 500
// response = 403; // Error: 403 is not assignable to StatusCode

// Practical example
const enum OrderPriority {
  Low = 'LOW',
  Medium = 'MEDIUM',
  High = 'HIGH'
}

function displayPriority(priority: OrderPriority): string {
  return `Order priority: ${priority}`;
}

let order: OrderPriority = OrderPriority.Low;
console.log(displayPriority(order)); // Order priority: LOW
order = OrderPriority.High;
console.log(displayPriority(order)); // Order priority: HIGH
// order = 'URGENT'; // Error: URGENT is not assignable to OrderPriority

// Security example
const enum Level {
  Beginner = 1,
  Intermediate = 2,
  Advanced = 3
}

function getLevelDescription(level: Level): string {
  return `Level: ${level}`;
}

let userLevel: Level = Level.Beginner;
console.log(getLevelDescription(userLevel)); // Level: 1
// userLevel = 4; // Error: 4 is not assignable to Level

// Error-prone example
let unsafe: any = 1;
console.log(unsafe); // 1, but no type safety
unsafe = 5; // Valid, but unsafe

// Correct approach
const enum Status {
  Online = 1,
  Offline = 2
}

let safeStatus: Status = Status.Online;
console.log(safeStatus); // 1
// safeStatus = 3; // Error: 3 is not assignable to Status

// Real-world scenario
const enum HttpStatus {
  OK = 200,
  BadRequest = 400,
  NotFound = 404,
  InternalError = 500
}

function processResponse(status: HttpStatus): string {
  return `Response status: ${status}`;
}

let response: HttpStatus = HttpStatus.OK;
console.log(processResponse(response)); // Response status: 200
response = HttpStatus.NotFound;
console.log(processResponse(response)); // Response status: 404
// response = 403; // Error: 403 is not assignable to HttpStatus

